/**
 * Registration Worksheet generation
 * A worksheet to help with copyright registration
 */

export function buildRegistrationWorksheet(data: {
  script: any;
  version: any;
}): string {
  const lines = [
    "Registration Worksheet",
    "Generated by DraftLock",
    "",
    "This worksheet organizes information that may be useful when registering copyright.",
    "DraftLock is not a law firm and does not provide legal advice.",
    "",
    "WORK INFORMATION",
    "",
    `Title of work: ${data.script.title || "Untitled"}`,
    `Work type: ${data.script.work_type || "—"}`,
    `Script ID: ${data.script.id}`,
    `Version ID: ${data.version.id}`,
    "",
    "FILE INFORMATION",
    "",
    `Original filename: ${data.version.original_filename || "—"}`,
    `File size: ${data.version.byte_size ? `${data.version.byte_size} bytes` : "—"}`,
    `MIME type: ${data.version.mime_type || "—"}`,
  ];

  if (data.version.page_count !== null) {
    lines.push(`Page count: ${data.version.page_count} ${data.version.page_count === 1 ? "page" : "pages"}`);
  }

  lines.push(
    "",
    "FINGERPRINT",
    "",
    `Algorithm: SHA-256`,
    `Hash: ${data.version.sha256 || "—"}`,
    "",
    "TIMESTAMP",
    "",
    `Committed at (UTC): ${data.version.committed_at ? new Date(data.version.committed_at).toISOString() : "—"}`,
    "",
    "AUTHORSHIP",
    "",
    `Authors count: ${data.script.authors_count || "—"}`,
    `Publication status: ${data.script.publication_status || "—"}`,
    `Work made for hire: ${data.script.work_made_for_hire || "—"}`,
    `Preexisting material: ${data.script.preexisting_material || "—"}`,
    "",
    "NOTES",
    "",
    data.script.notes || "No notes provided.",
    "",
    "DISCLAIMER",
    "",
    "This worksheet is provided for organizational purposes only.",
    "It does not constitute legal advice or a government registration.",
    "For official registration, follow the instructions provided by the",
    "U.S. Copyright Office or consult with a qualified attorney.",
    "",
    "DraftLock is not a law firm and does not provide legal advice."
  );

  return lines.join("\n");
}
